let items=$input.all(),r=[];
for(let it of items){
 let msg=it.json,from='',sub='',email='',name='';
 if(msg.from||msg.From){from=msg.from||msg.From||''}
 if(msg.subject||msg.Subject){sub=msg.subject||msg.Subject||''}
 if(!from&&msg.payload&&msg.payload.headers){
  let h=msg.payload.headers;
  if(Array.isArray(h)){
   let f=h.find(x=>x&&x.name==='From'),s=h.find(x=>x&&x.name==='Subject');
   from=f?f.value||'':'';sub=sub||(s?s.value||'':'');
  }else{from=h.from||h.From||'';sub=sub||h.subject||h.Subject||''}
 }
 if(!from){r.push({json:{_skip:true}});continue}
 let m=from.match(/<?([^>]+)>?/);email=m?m[1].trim():from.trim();
 let nm=from.match(/^([^<]*)/);name=(nm&&nm[1])?nm[1].trim().replace(/"/g,''):from.split('<')[0].trim().replace(/"/g,'');
 if(!name)name=email;
 let body=msg.snippet||'';if(!sub)sub='(no subject)';
 let prompt='You are Digital Clone. Classify this email:\nFrom: '+name+' ('+email+')\nSubject: '+sub+'\n'+body.substring(0,600)+'\n\nIf this needs MY personal reply, say NEEDS_REPLY and draft a reply under 300 chars. If it is just informational/no action needed, say INFO_ONLY.';
 r.push({json:{_prompt:prompt,_name:name,_email:email,_sub:sub,_snippet:body.substring(0,120),_mid:msg.id||'',_tid:msg.threadId||''}})
}
return r

let items=$input.all(),r=[];
